Pester est le framework de test officiel pour PowerShell :

```powershell
# Installer Pester
Install-Module Pester -Force -Scope CurrentUser

# Structure d'un test Pester
Describe "MaFonction" {
    Context "cas normaux" {
        It "retourne la somme" {
            # Arrange
            $a = 3; $b = 4

            # Act
            $result = $a + $b

            # Assert
            $result | Should -Be 7
        }

        It "retourne le bon type" {
            (2 + 2) | Should -BeOfType [int]
        }
    }

    Context "cas d'erreur" {
        It "throw sur division par zéro" {
            { 1/0 } | Should -Throw
        }
    }
}
```

```powershell
# Mock : remplacer une commande par un faux
Describe "Get-UserInfo" {
    BeforeAll {
        function Get-UserInfo {
            param($name)
            $user = Get-ADUser -Identity $name  # cmd réelle
            return $user.Department
        }
    }

    It "retourne le département" {
        # Remplacer Get-ADUser par un faux
        Mock Get-ADUser {
            return [PSCustomObject]@{ Department = 'IT' }
        }

        $result = Get-UserInfo -name "alice"
        $result | Should -Be 'IT'

        # Vérifier que le mock a été appelé
        Assert-MockCalled Get-ADUser -Times 1
        Assert-MockCalled Get-ADUser -ParameterFilter { $Identity -eq 'alice' }
    }
}

# Mock avec conditions
Mock Invoke-RestMethod {
    return @{ status = 'ok'; data = @() }
} -ParameterFilter { $Uri -match '/api/users' }
```

```powershell
Describe "Gestion fichiers" {
    BeforeAll {
        # Exécuté une fois avant tous les tests
        $testDir = Join-Path $TestDrive "tests"
        New-Item -ItemType Directory -Path $testDir
    }

    AfterAll {
        # Exécuté une fois après tous les tests
        Remove-Item $testDir -Recurse -Force -ErrorAction SilentlyContinue
    }

    BeforeEach {
        # Exécuté avant CHAQUE test
        $testFile = Join-Path $testDir "test.txt"
        Set-Content $testFile "contenu initial"
    }

    AfterEach {
        # Nettoyage après chaque test
        Remove-Item $testFile -ErrorAction SilentlyContinue
    }

    It "lit le contenu" {
        $content = Get-Content $testFile
        $content | Should -Be "contenu initial"
    }

    It "modifie le contenu" {
        Set-Content $testFile "nouveau contenu"
        Get-Content $testFile | Should -Be "nouveau contenu"
    }
}
```

**`$TestDrive`** : dossier temporaire géré par Pester, nettoyé automatiquement.

