Describe "Tests de base" {
    It "addition" {
        (2 + 2) | Should -Be 4
    }
    It "pattern matching" {
        "hello" | Should -BeLike "hel*"
    }
    It "tableau count" {
        @(1,2,3) | Should -HaveCount 3
    }
}

$result = Invoke-Pester -PassThru -Output None
Write-Host "Passed: $($result.PassedCount), Failed: $($result.FailedCount)"

function Get-Factorielle {
    param([int]$n)
    if ($n -le 1) { return 1 }
    return $n * (Get-Factorielle ($n - 1))
}

Describe "Get-Factorielle" {
    It "factorielle de 0" {
        Get-Factorielle 0 | Should -Be 1
    }
    It "factorielle de 5" {
        Get-Factorielle 5 | Should -Be 120
    }
    It "factorielle de 1" {
        Get-Factorielle 1 | Should -Be 1
    }
}

$result = Invoke-Pester -PassThru -Output None
Write-Host "Passed: $($result.PassedCount), Failed: $($result.FailedCount)"

function Diviser {
    param([double]$a, [double]$b)
    if ($b -eq 0) { throw "Division par zéro impossible" }
    return $a / $b
}

Describe "Diviser" {
    It "division normale" {
        Diviser 10 2 | Should -Be 5
    }
    It "division par zéro throw" {
        { Diviser 10 0 } | Should -Throw -ExpectedMessage "zéro"
    }
}

$result = Invoke-Pester -PassThru -Output None
Write-Host "Passed: $($result.PassedCount), Failed: $($result.FailedCount)"
